def gen(rng, size):
    import string
    alpha = 'abcde'
    words = []
    for _ in range(14):
        length = rng.randint(3, 8)
        words.append(''.join(rng.choice(alpha) for _ in range(length)))
    supply = {}
    for w in words:
        for ch in w:
            supply[ch] = supply.get(ch, 0) + 1
    # give exactly the supply of each letter so all words are marginally affordable
    letters = []
    for ch, cnt in supply.items():
        letters.extend([ch] * cnt)
    score = [rng.randint(0, 10) for _ in range(26)]
    return [words, letters, score]

