class Solution:
    def maxScoreWords(self, words, letters, score):
        from collections import Counter
        supply = Counter(letters)
        n = len(words)
        best = 0
        for mask in range(1 << n):
            freq = Counter()
            total = 0
            valid = True
            for i in range(n):
                if mask >> i & 1:
                    for ch in words[i]:
                        freq[ch] += 1
                        total += score[ord(ch) - ord('a')]
            for ch, cnt in freq.items():
                if supply[ch] < cnt:
                    valid = False
                    break
            if valid:
                best = max(best, total)
        return best

