var maxScoreWords = function(words, letters, score) {
    const supply = new Array(26).fill(0);
    for (const ch of letters) supply[ch.charCodeAt(0) - 97]++;
    const n = words.length;
    let best = 0;
    for (let mask = 0; mask < (1 << n); mask++) {
        const freq = new Array(26).fill(0);
        let total = 0;
        let valid = true;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                for (const ch of words[i]) {
                    freq[ch.charCodeAt(0) - 97]++;
                    total += score[ch.charCodeAt(0) - 97];
                }
            }
        }
        for (let c = 0; c < 26; c++) {
            if (freq[c] > supply[c]) { valid = false; break; }
        }
        if (valid) best = Math.max(best, total);
    }
    return best;
};
